checker_dsl:
EXISTS (`IfStmt if1`, `IfStmt if2`, `SynchronizedStmt sync`, `Field f`) {
  AND {
    (`if1's then branch directly or indirectly encloses sync`),
    (`sync's block directly or indirectly encloses if2`),
    EXISTS (`Expr nullCheck1`) {
      AND {
        (`nullCheck1 is an equality test with polarity true (==)`),
        EXISTS (`NullLiteral nl`, `Expr fieldRead1`) {
          AND {
            (`the equality test has operands nl and fieldRead1`),
            (`fieldRead1 is a read access of field f`)
          }
        },
        (`if1's condition is nullCheck1`)
      }
    },
    EXISTS (`Expr nullCheck2`) {
      AND {
        (`nullCheck2 is an equality test with polarity true (==)`),
        EXISTS (`NullLiteral nl2`, `Expr fieldRead2`) {
          AND {
            (`the equality test has operands nl2 and fieldRead2`),
            (`fieldRead2 is a read access of field f`)
          }
        },
        (`if2's condition is nullCheck2`)
      }
    },
    NOT { (`field f is volatile`) },
    NOT {
      AND {
        OR {
          (`all fields of f's type are final`),
          (`f's type is an ImmutableType`)
        },
        (`the count of field accesses to f within sync's enclosing callable that are NOT inside sync's block is exactly 1`)
      }
    }
  }
}
